// All 50 US states — data for programmatic Korean-business state landing pages.
// Population = "Korean alone or in combination" ACS-style estimates (approximate).
// `distinct` carries the named local anchor (H Mart, corridor street) that makes
// each page unique content and defensible against thin/duplicate-content flags.

export type StateData = {
  abbr: string
  slug: string // matches existing pattern: "<abbr>-website"
  koSlug: string // Korean route slug, e.g. '콜로라도-웹사이트'
  name: { en: string; ko: string }
  koreanPopulation: string
  tier: 'large' | 'medium' | 'small' | 'minimal'
  cities: { en: string; ko: string }[]
  metro: { en: string; ko: string }
  distinct: { en: string; ko: string }
  neighbors: string[] // 2-4 neighboring state abbrs (lowercase, matching abbr values above)
  industries: { en: string; ko: string }[] // common Korean-American business types in the state
  secondParagraph: { en: string; ko: string } // one additional unique paragraph per state
}

const C = (en: string, ko: string) => ({ en, ko })

